declare(strict_types=1);require_once __DIR__.'/config/config.php';require_once ROOT_PATH.'/functions/approval_functions.php';if(currentUser())redirect('dashboard.php');if($_SERVER['REQUEST_METHOD']==='POST'){try{if(!verifyCsrfToken((string)($_POST['csrf_token']??'')))throw new RuntimeException('Your form session expired.');registerPendingUser($_POST);setFlash('success','Your registration request has been submitted successfully. Your account is under review; you will be notified once approved.');redirect('login.php');}catch(Throwable $e){setFlash('danger',$e->getMessage());}}
require ROOT_PATH.'/includes/header.php';?><main class="auth-shell"><section class="auth-card card"><h2>Request TransitOps access</h2><p>Accounts are activated after Administrator or Fleet Manager approval.</p><form method="post"><input type="hidden" name="csrf_token" value="<?=e(csrfToken())?>"><div class="form-grid"><?php foreach(['first_name'=>'First name','last_name'=>'Last name','employee_id'=>'Employee ID','email'=>'Email','phone'=>'Phone','department'=>'Department','address'=>'Address','city'=>'City','state'=>'State','country'=>'Country'] as $name=>$label):?><div class="form-group"><label><?=e($label)?></label><input name="<?=$name?>" type="<?=$name==='email'?'email':'text'?>" <?=in_array($name,['first_name','last_name','email','phone','department'],true)?'required':''?>></div><?php endforeach;?><div class="form-group"><label>Requested role</label><select name="role"><?php foreach(requestedRoles() as $key=>$label):?><option value="<?=e($key)?>"><?=e($label)?></option><?php endforeach;?></select></div><div class="form-group"><label>Password</label><input name="password" type="password" required></div><div class="form-group"><label>Confirm password</label><input name="password_confirmation" type="password" required></div></div><button class="btn btn-primary">Submit registration request</button><a class="auth-link" href="login.php">Back to sign in</a></form></section></main><?php require ROOT_PATH.'/includes/footer.php';?>
